    def _calculate_3d_positions(self, bubbles: List[Dict]) -> List[Dict]:
        """
        Calculate 3D positions for bubbles using force-directed layout
        Similar to how BubbleMaps works but in 3D
        """
        positions = []
        n = len(bubbles)

        # Use spherical distribution with force simulation
        for i, bubble in enumerate(bubbles):
            # Base position on sphere
            phi = np.arccos(1 - 2 * (i + 0.5) / n)
            theta = np.pi * (1 + 5**0.5) * i

            # Radius based on holder percentage (whales closer to center)
            base_radius = 80
            radius = base_radius - (bubble.get('pct', 0) * 3)  # Bigger holders closer

            x = radius * np.sin(phi) * np.cos(theta)
            y = radius * np.sin(phi) * np.sin(theta)
            z = radius * np.cos(phi)

            positions.append({'x': x, 'y': y, 'z': z})

        return positions

